import React, { useEffect } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import InvoiceManager from './components/InvoiceManager';
import ClientManager from './components/ClientManager';
import SupplierManager from './components/SupplierManager';
import ProductManager from './components/ProductManager';
import AccountingManager from './components/AccountingManager';
import EmailManager from './components/EmailManager';
import CalendarManager from './components/CalendarManager';
import SettingsManager from './components/SettingsManager';
import AIAssistant from './components/AIAssistant';
import { Menu, LogIn, LogOut, Loader2, Sun, Moon, Mail, ArrowRight, CheckCircle2 } from 'lucide-react';
import { onAuthStateChanged } from 'firebase/auth';
import {
  collection,
  query,
  where,
  onSnapshot,
  doc,
  setDoc,
  deleteDoc
} from 'firebase/firestore';
import { auth, db, loginWithGoogle, logout, OperationType, handleFirestoreError } from './firebase';
import { useAppStore } from './store/appStore';
import {
  Invoice,
  Client,
  Supplier,
  Product,
  Expense,
  Email,
  EmailTemplate,
  CalendarEvent,
  UserProfile
} from './types';

const App: React.FC = () => {
  // ─── ZUSTAND GLOBAL STATE ───
  const {
    // UI
    currentView,
    setCurrentView,
    isMobileMenuOpen,
    setIsMobileMenuOpen,
    isDarkMode,
    setIsDarkMode,
    // Auth
    user,
    setUser,
    isAuthReady,
    setIsAuthReady,
    // Data
    invoices,
    setInvoices,
    clients,
    setClients,
    suppliers,
    setSuppliers,
    products,
    setProducts,
    expenses,
    setExpenses,
    emails,
    setEmails,
    emailTemplates,
    setEmailTemplates,
    calendarEvents,
    setCalendarEvents,
    userProfile,
    setUserProfile,
  } = useAppStore();

  // ─── AUTH SETUP ───
  useEffect(() => {
    const unsubscribe = onAuthStateChanged(auth, (currentUser) => {
      setUser(currentUser);
      setIsAuthReady(true);
    });
    return () => unsubscribe();
  }, [setUser, setIsAuthReady]);

  // ─── FIRESTORE SYNC (Update Zustand on data changes) ───
  useEffect(() => {
    if (!user) return;

    const qInvoices = query(collection(db, 'invoices'), where('uid', '==', user.uid));
    const unsubInvoices = onSnapshot(qInvoices, (snapshot) => {
      setInvoices(snapshot.docs.map(doc => doc.data() as Invoice));
    }, () => handleFirestoreError(null, OperationType.LIST, 'invoices'));

    const qClients = query(collection(db, 'clients'), where('uid', '==', user.uid));
    const unsubClients = onSnapshot(qClients, (snapshot) => {
      setClients(snapshot.docs.map(doc => doc.data() as Client));
    }, () => handleFirestoreError(null, OperationType.LIST, 'clients'));

    const qSuppliers = query(collection(db, 'suppliers'), where('uid', '==', user.uid));
    const unsubSuppliers = onSnapshot(qSuppliers, (snapshot) => {
      setSuppliers(snapshot.docs.map(doc => doc.data() as Supplier));
    }, () => handleFirestoreError(null, OperationType.LIST, 'suppliers'));

    const qProducts = query(collection(db, 'products'), where('uid', '==', user.uid));
    const unsubProducts = onSnapshot(qProducts, (snapshot) => {
      setProducts(snapshot.docs.map(doc => doc.data() as Product));
    }, () => handleFirestoreError(null, OperationType.LIST, 'products'));

    const qExpenses = query(collection(db, 'expenses'), where('uid', '==', user.uid));
    const unsubExpenses = onSnapshot(qExpenses, (snapshot) => {
      setExpenses(snapshot.docs.map(doc => doc.data() as Expense));
    }, () => handleFirestoreError(null, OperationType.LIST, 'expenses'));

    const qEmails = query(collection(db, 'emails'), where('uid', '==', user.uid));
    const unsubEmails = onSnapshot(qEmails, (snapshot) => {
      setEmails(snapshot.docs.map(doc => doc.data() as Email));
    }, () => handleFirestoreError(null, OperationType.LIST, 'emails'));

    const qTemplates = query(collection(db, 'emailTemplates'), where('uid', '==', user.uid));
    const unsubTemplates = onSnapshot(qTemplates, (snapshot) => {
      setEmailTemplates(snapshot.docs.map(doc => doc.data() as EmailTemplate));
    }, () => handleFirestoreError(null, OperationType.LIST, 'emailTemplates'));

    const qEvents = query(collection(db, 'calendarEvents'), where('uid', '==', user.uid));
    const unsubEvents = onSnapshot(qEvents, (snapshot) => {
      setCalendarEvents(snapshot.docs.map(doc => doc.data() as CalendarEvent));
    }, () => handleFirestoreError(null, OperationType.LIST, 'calendarEvents'));

    // Profile sync
    const unsubProfile = onSnapshot(doc(db, 'profiles', user.uid), (docSnap) => {
      if (docSnap.exists()) {
        setUserProfile(docSnap.data() as UserProfile);
      }
    }, () => handleFirestoreError(null, OperationType.GET, `profiles/${user.uid}`));

    return () => {
      unsubInvoices();
      unsubClients();
      unsubSuppliers();
      unsubProducts();
      unsubExpenses();
      unsubEmails();
      unsubTemplates();
      unsubEvents();
      unsubProfile();
    };
  }, [user, setInvoices, setClients, setSuppliers, setProducts, setExpenses, setEmails, setEmailTemplates, setCalendarEvents, setUserProfile]);

  // ─── FIRESTORE HELPERS ───
  const saveDoc = async (collectionName: string, data: any) => {
    if (!user) return;
    try {
      await setDoc(doc(db, collectionName, data.id), { ...data, uid: user.uid });
    } catch (err) {
      handleFirestoreError(err, OperationType.WRITE, `${collectionName}/${data.id}`);
    }
  };

  const deleteDocFromFirestore = async (collectionName: string, id: string) => {
    if (!user) return;
    try {
      await deleteDoc(doc(db, collectionName, id));
    } catch (err) {
      handleFirestoreError(err, OperationType.DELETE, `${collectionName}/${id}`);
    }
  };

  const renderContent = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard invoices={invoices} products={products} expenses={expenses} emails={emails} events={calendarEvents} onNavigate={setCurrentView} userProfile={userProfile} onSaveInvoice={(inv) => saveDoc('invoices', inv)} />;
      case 'invoices':
        return (
          <InvoiceManager
            invoices={invoices}
            setInvoices={(newInvoices) => {
              // This is a bit complex because InvoiceManager uses setInvoices for everything
              // For now, let's just update the state and we'll need to update the component to use saveDoc
              setInvoices(newInvoices);
            }}
            clients={clients}
            userProfile={userProfile}
            products={products}
            onSave={(inv) => saveDoc('invoices', inv)}
            onDelete={(id) => deleteDocFromFirestore('invoices', id)}
          />
        );
      case 'clients':
        return (
          <ClientManager
            clients={clients}
            setClients={setClients}
            invoices={invoices}
            onSave={(c) => saveDoc('clients', c)}
            onDelete={(id) => deleteDocFromFirestore('clients', id)}
          />
        );
      case 'suppliers':
        return (
          <SupplierManager
            suppliers={suppliers}
            setSuppliers={setSuppliers}
            expenses={expenses}
            onSave={(s) => saveDoc('suppliers', s)}
            onDelete={(id) => deleteDocFromFirestore('suppliers', id)}
          />
        );
      case 'products':
        return (
          <ProductManager
            products={products}
            setProducts={setProducts}
            onSave={(p) => saveDoc('products', p)}
            onDelete={(id) => deleteDocFromFirestore('products', id)}
          />
        );
      case 'accounting':
        return (
          <AccountingManager
            expenses={expenses}
            setExpenses={setExpenses}
            invoices={invoices}
            suppliers={suppliers}
            userProfile={userProfile}
            clients={clients}
            onSaveExpense={(e) => saveDoc('expenses', e)}
            onDeleteExpense={(id) => deleteDocFromFirestore('expenses', id)}
          />
        );
      case 'emails':
        return (
          <EmailManager
            emails={emails}
            setEmails={setEmails}
            templates={emailTemplates}
            setTemplates={setEmailTemplates}
            clients={clients}
            invoices={invoices}
            userProfile={userProfile}
            onSaveEmail={(e) => saveDoc('emails', e)}
            onDeleteEmail={(id) => deleteDocFromFirestore('emails', id)}
            onSaveTemplate={(t) => saveDoc('emailTemplates', t)}
            onDeleteTemplate={(id) => deleteDocFromFirestore('emailTemplates', id)}
          />
        );
      case 'calendar':
        return (
          <CalendarManager
            events={calendarEvents}
            setEvents={setCalendarEvents}
            clients={clients}
            invoices={invoices}
            onSaveEvent={(e) => saveDoc('calendarEvents', e)}
            onDeleteEvent={(id) => deleteDocFromFirestore('calendarEvents', id)}
          />
        );
      case 'settings':
        return (
          <SettingsManager
            userProfile={userProfile}
            setUserProfile={setUserProfile}
            onSaveProfile={(p) => {
              if (user) {
                setDoc(doc(db, 'profiles', user.uid), { ...p, uid: user.uid })
                  .catch(err => handleFirestoreError(err, OperationType.WRITE, `profiles/${user.uid}`));
              }
            }}
            allData={{
              invoices,
              clients,
              suppliers,
              products,
              expenses
            }}
            setAllData={{
              setInvoices,
              setClients,
              setSuppliers,
              setProducts,
              setExpenses
            }}
          />
        );
      case 'ai_assistant':
        return <AIAssistant />;
      default:
        return <Dashboard invoices={invoices} products={products} expenses={expenses} emails={emails} events={calendarEvents} onNavigate={setCurrentView} userProfile={userProfile} />;
    }
  };

  const [emailLink, setEmailLinkState] = React.useState('');
  const [isEmailSent, setIsEmailSent] = React.useState(false);
  const [isSending, setIsSending] = React.useState(false);

  if (!isAuthReady) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50">
        <Loader2 className="w-10 h-10 text-brand-600 animate-spin" />
      </div>
    );
  }

  if (!user) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-brand-50 dark:bg-brand-950 p-6 transition-colors duration-500">
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute -top-24 -left-24 w-96 h-96 bg-brand-200/30 dark:bg-brand-800/20 rounded-full blur-3xl animate-pulse" />
          <div className="absolute -bottom-24 -right-24 w-96 h-96 bg-accent-200/30 dark:bg-accent-800/20 rounded-full blur-3xl animate-pulse delay-700" />
        </div>

        <div className="max-w-md w-full glass p-10 rounded-[2.5rem] shadow-2xl text-center border border-white/40 dark:border-white/5 relative z-10 animate-fade-in">
          <div className="w-24 h-24 bg-brand-900 dark:bg-brand-800 rounded-3xl flex items-center justify-center mx-auto mb-10 shadow-2xl rotate-6 hover:rotate-0 transition-transform duration-500">
            <LogIn className="text-white" size={48} />
          </div>
          <h1 className="text-4xl font-bold text-brand-900 dark:text-white mb-4 tracking-tight">Micro Gestion</h1>
          <p className="text-brand-600 dark:text-brand-300 mb-12 text-lg">Votre allié quotidien pour une gestion simplifiée et intelligente.</p>

          <div className="space-y-4">
            <button
              onClick={loginWithGoogle}
              className="w-full py-4 px-8 bg-brand-900 dark:bg-white text-white dark:text-brand-900 rounded-2xl font-bold flex items-center justify-center gap-4 hover:scale-[1.02] active:scale-95 transition-all shadow-xl hover:shadow-brand-900/20 dark:hover:shadow-white/10 group mb-6"
            >
              <LogIn size={24} className="group-hover:translate-x-1 transition-transform" />
              Se connecter avec Google
            </button>

            <div className="relative my-8">
              <div className="absolute inset-0 flex items-center">
                <div className="w-full border-t border-brand-200 dark:border-brand-800"></div>
              </div>
              <div className="relative flex justify-center text-xs uppercase">
                <span className="bg-brand-50 dark:bg-brand-950 px-4 text-brand-400 font-bold tracking-widest">OU</span>
              </div>
            </div>

            {!isEmailSent ? (
              <form
                onSubmit={async (e) => {
                  e.preventDefault();
                  if (!emailLink || isSending) return;
                  setIsSending(true);
                  try {
                    await sendEmailLink(emailLink);
                    setIsEmailSent(true);
                  } catch (err) {
                    alert("Erreur lors de l'envoi du lien.");
                  } finally {
                    setIsSending(false);
                  }
                }}
                className="space-y-3"
              >
                <div className="relative">
                  <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-brand-400" size={20} />
                  <input
                    type="email"
                    placeholder="votre@email.com"
                    required
                    value={emailLink}
                    onChange={(e) => setEmailLinkState(e.target.value)}
                    className="w-full pl-12 pr-4 py-4 bg-white dark:bg-brand-900/50 border border-brand-200 dark:border-brand-800 rounded-2xl focus:ring-4 focus:ring-brand-500/10 focus:border-brand-500 outline-none transition-all dark:text-white"
                  />
                </div>
                <button
                  type="submit"
                  disabled={isSending}
                  className="w-full py-4 bg-brand-50 dark:bg-brand-800 text-brand-900 dark:text-white rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-brand-100 dark:hover:bg-brand-700 transition-all border border-brand-200 dark:border-brand-700 group"
                >
                  {isSending ? 'Envoi...' : 'Recevoir un lien magique'}
                  <ArrowRight size={18} className="group-hover:translate-x-1 transition-transform" />
                </button>
              </form>
            ) : (
              <div className="p-6 bg-green-50 dark:bg-green-900/20 border border-green-100 dark:border-green-800 rounded-[2rem] text-center animate-fade-in">
                <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center mx-auto mb-4 text-white shadow-lg shadow-green-500/20">
                  <CheckCircle2 size={24} />
                </div>
                <h3 className="text-green-800 dark:text-green-300 font-bold mb-1">Lien envoyé !</h3>
                <p className="text-sm text-green-700 dark:text-green-400">Consultez vos e-mails pour vous connecter.</p>
                <button
                  onClick={() => setIsEmailSent(false)}
                  className="mt-4 text-xs font-bold text-green-600 uppercase tracking-widest hover:underline"
                >
                  Renvoyer ou changer d'e-mail
                </button>
              </div>
            )}
          </div>

          <p className="mt-10 text-xs text-brand-400 dark:text-brand-500 uppercase tracking-widest font-semibold">Sécurisé par Google Auth</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex min-h-screen bg-brand-50 dark:bg-brand-950 font-sans text-brand-900 dark:text-brand-50 selection:bg-brand-200 dark:selection:bg-brand-800 selection:text-brand-900 transition-colors duration-500">
      <Sidebar
        currentView={currentView}
        setView={setCurrentView}
        isMobileMenuOpen={isMobileMenuOpen}
        setIsMobileMenuOpen={setIsMobileMenuOpen}
        isDarkMode={isDarkMode}
        toggleDarkMode={() => setIsDarkMode(!isDarkMode)}
      />

      <main className="flex-1 lg:ml-64 p-4 lg:p-8 xl:p-12 overflow-x-hidden">
        {/* Mobile Header */}
        <div className="lg:hidden flex justify-between items-center mb-8 sticky top-0 bg-brand-50/80 dark:bg-brand-950/80 backdrop-blur-md z-30 py-4 border-b border-brand-200/50 dark:border-brand-800/50">
          <h1 className="text-xl font-bold text-brand-900 dark:text-white tracking-tight">Micro Gestion</h1>
          <div className="flex gap-2">
            <button
              onClick={() => setIsDarkMode(!isDarkMode)}
              className="p-2.5 bg-white dark:bg-brand-900 rounded-xl shadow-sm border border-brand-200 dark:border-brand-800 text-brand-600 dark:text-brand-200 hover:bg-brand-50 transition-colors"
              title="Changer de thème"
            >
              {isDarkMode ? <Sun size={20} /> : <Moon size={20} />}
            </button>
            <button
              onClick={() => setIsMobileMenuOpen(true)}
              className="p-2.5 bg-brand-900 text-white rounded-xl shadow-lg hover:bg-brand-800 transition-all active:scale-90"
              title="Ouvrir le menu"
            >
              <Menu size={20} />
            </button>
          </div>
        </div>

        {/* Desktop Header / Top Bar */}
        <div className="hidden lg:flex justify-end items-center gap-6 mb-10 animate-fade-in">
           <div className="flex items-center gap-4 px-4 py-2 bg-white/50 dark:bg-brand-900/50 backdrop-blur-sm rounded-2xl border border-brand-100 dark:border-brand-800 shadow-sm">
             <div className="flex flex-col items-end">
               <span className="text-xs font-semibold text-brand-400 dark:text-brand-500 uppercase tracking-wider">Connecté en tant que</span>
               <span className="text-sm font-bold text-brand-900 dark:text-brand-100">{user.displayName || user.email}</span>
             </div>
             <div className="w-10 h-10 rounded-xl bg-brand-100 dark:bg-brand-800 flex items-center justify-center overflow-hidden border border-brand-200 dark:border-brand-700">
               {user.photoURL ? (
                 <img src={user.photoURL} alt="Avatar" className="w-full h-full object-cover" referrerPolicy="no-referrer" />
               ) : (
                 <span className="text-brand-600 dark:text-brand-200 font-bold">{user.email?.[0].toUpperCase()}</span>
               )}
             </div>
             <div className="w-px h-8 bg-brand-200 dark:bg-brand-800 mx-1" />
             <button
                onClick={logout}
                className="p-2 text-brand-400 hover:text-red-500 dark:hover:text-red-400 transition-all hover:bg-red-50 dark:hover:bg-red-900/20 rounded-xl"
                title="Déconnexion"
              >
                <LogOut size={20} />
              </button>
           </div>
        </div>

        <div className="animate-slide-up">
          {renderContent()}
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { generateAssistantResponse } from '../services/geminiService';
import { Send, Bot, User, Sparkles } from 'lucide-react';

const AIAssistant: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      role: 'model',
      content: "Bonjour ! Je suis votre assistant administratif virtuel. Je peux vous aider avec vos questions sur le statut auto-entrepreneur, les déclarations URSSAF, ou la rédaction de courriers. Comment puis-je vous aider aujourd'hui ?",
      timestamp: Date.now()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMsg: ChatMessage = { role: 'user', content: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    // Build context from last few messages
    const context = messages.slice(-3).map(m => `${m.role}: ${m.content}`).join('\n');

    const responseText = await generateAssistantResponse(userMsg.content, context);

    const modelMsg: ChatMessage = { role: 'model', content: responseText, timestamp: Date.now() };
    setMessages(prev => [...prev, modelMsg]);
    setIsLoading(false);
  };

  return (
    <div className="h-[calc(100vh-6rem)] max-w-5xl mx-auto flex flex-col bg-white rounded-[2rem] shadow-xl border border-brand-200 overflow-hidden animate-fade-in">
      <div className="bg-gradient-to-r from-brand-900 to-brand-800 p-6 flex items-center justify-between">
        <div className="flex items-center gap-4">
            <div className="p-2.5 bg-white/20 backdrop-blur-md rounded-xl shadow-inner">
                <Sparkles className="text-white" size={24} />
            </div>
            <div>
                <h2 className="text-white font-bold text-lg">Assistant Administratif</h2>
                <div className="flex items-center gap-2">
                    <span className="relative flex h-2 w-2">
                    <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-accent-400 opacity-75"></span>
                    <span className="relative inline-flex rounded-full h-2 w-2 bg-accent-500"></span>
                    </span>
                    <p className="text-brand-100 text-xs font-medium">En ligne • Propulsé par Google Gemini</p>
                </div>
            </div>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-brand-50/30 scroll-smooth">
        {messages.map((msg, idx) => (
          <div
            key={idx}
            className={`flex items-start gap-4 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
          >
            <div className={`
              w-10 h-10 rounded-full flex items-center justify-center shrink-0 shadow-sm border
              ${msg.role === 'user' ? 'bg-brand-900 border-brand-800 text-white' : 'bg-white border-brand-200 text-brand-600'}
            `}>
              {msg.role === 'user' ? <User size={18} /> : <Bot size={20} />}
            </div>

            <div className={`flex flex-col ${msg.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`
                max-w-[85%] px-5 py-3.5 text-sm leading-relaxed whitespace-pre-wrap shadow-sm
                ${msg.role === 'user'
                    ? 'bg-brand-900 text-white rounded-[2rem] rounded-tr-sm'
                    : 'bg-white text-brand-800 rounded-[2rem] rounded-tl-sm border border-brand-100'}
                `}>
                {msg.content}
                </div>
                <span className="text-[10px] text-brand-400 mt-1 px-1">
                    {new Date(msg.timestamp).toLocaleTimeString([], {hour: '2-digit', minute:'2-digit'})}
                </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex items-start gap-4">
             <div className="w-10 h-10 rounded-full bg-white border border-brand-200 text-brand-600 flex items-center justify-center shrink-0 shadow-sm">
               <Bot size={20} />
             </div>
             <div className="bg-white px-5 py-4 rounded-[2rem] rounded-tl-sm border border-brand-100 shadow-sm">
               <div className="flex gap-1.5">
                 <div className="w-2 h-2 bg-accent-400 rounded-full animate-bounce"></div>
                 <div className="w-2 h-2 bg-accent-400 rounded-full animate-bounce [animation-delay:-.15s]"></div>
                 <div className="w-2 h-2 bg-accent-400 rounded-full animate-bounce [animation-delay:-.3s]"></div>
               </div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSend} className="p-6 bg-white border-t border-brand-100">
        <div className="relative flex gap-3">
          <input
            type="text"
            className="flex-1 pl-5 pr-12 py-3.5 border border-brand-200 rounded-2xl focus:ring-2 focus:ring-accent-500/20 focus:border-accent-500 outline-none transition-all shadow-sm bg-brand-50/50 focus:bg-white"
            placeholder="Posez une question (ex: Comment déclarer mon CA ?)"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            disabled={isLoading}
          />
          <button
            type="submit"
            disabled={isLoading || !input.trim()}
            className="px-6 py-3.5 bg-brand-900 text-white rounded-2xl hover:bg-brand-800 disabled:opacity-50 disabled:hover:bg-brand-900 transition-all font-bold shadow-md flex items-center gap-2"
          >
            <span>Envoyer</span>
            <Send size={18} />
          </button>
        </div>
        <div className="text-center mt-3">
            <p className="text-[10px] text-brand-400 flex items-center justify-center gap-1.5">
                <MessageSquare size={10} />
                L'IA peut commettre des erreurs. Vérifiez toujours les informations légales.
            </p>
        </div>
      </form>
    </div>
  );
};

export default AIAssistant;
